mapper.select:
SELECT p.*, c.name AS category_name,
       u.id AS seller_user_id, u.nickname AS seller_nickname,
       u.username AS seller_username, u.avatar AS seller_avatar,
       u.credit_score AS seller_credit_score
FROM product p
LEFT JOIN category c ON p.category_id = c.id
LEFT JOIN user u ON p.user_id = u.id
WHERE p.deleted_at IS NULL

    AND p.status = #{status}


    AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))


    AND p.category_id IN (
        SELECT id FROM category
        WHERE id = #{categoryId}
           OR parent_id = #{categoryId}
    )


    AND p.price >= #{minPrice}


    AND p.price <= #{maxPrice}


    AND p.condition = #{condition}


    AND p.user_id = #{userId}


    
        ORDER BY p.${sort} ${order}
    
    
        ORDER BY p.created_at DESC

